    fused = str(op.options.get("fusedActivationFunction", "NONE"))
    if op_type in {"CONV_2D", "DEPTHWISE_CONV_2D"}:
        conv_input_name = str(op.inputs[0])
        conv_input_expr = tensor_expr_fn(conv_input_name)
